import{_ as t,c as a,S as s,o as i}from"./chunks/framework.BjmDYXuv.js";const k=JSON.parse('{"title":"Leaderboard","description":"","frontmatter":{},"headers":[],"relativePath":"spaces/leaderboard.md","filePath":"spaces/leaderboard.md","lastUpdated":1776166058000}'),r={name:"spaces/leaderboard.md"};function l(n,e,o,d,h,c){return i(),a("div",null,e[0]||(e[0]=[s(`<h1 id="leaderboard" tabindex="-1">Leaderboard <a class="header-anchor" href="#leaderboard" aria-label="Permalink to &quot;Leaderboard&quot;">​</a></h1><p><strong>Live:</strong> <a href="https://huggingface.co/spaces/CERN/colliderml-leaderboard" target="_blank" rel="noreferrer">huggingface.co/spaces/CERN/colliderml-leaderboard</a><strong>Source:</strong> <a href="https://github.com/OpenDataDetector/ColliderML/tree/main/spaces/leaderboard" target="_blank" rel="noreferrer"><code>spaces/leaderboard/</code></a></p><p>Public scoreboard for the six benchmark tasks shipped in <a href="./../library/tasks.html"><code>colliderml.tasks</code></a>. Browse rankings, submit your own predictions, or reproduce someone else&#39;s to earn credits.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>One tab per task. Inside each tab you get:</p><ol><li>A table of the top 100 submissions (sortable, read-only). Columns include submitter HF username, all task metrics, credits earned for that submission, and whether it&#39;s a shipped baseline.</li><li>A <strong>Submit predictions</strong> accordion — upload a parquet file, the backend re-scores it against held-out truth, and any metric that beats the current best earns credits.</li><li>A <strong>Reproduce a submission</strong> accordion — enter a submission ID and upload your own predictions. If every metric lands within 2% of the original you earn 20 credits. This is the self-policing mechanism that keeps the board honest.</li></ol><h2 id="task-discovery" tabindex="-1">Task discovery <a class="header-anchor" href="#task-discovery" aria-label="Permalink to &quot;Task discovery&quot;">​</a></h2><p>The task list is loaded from the installed <a href="./../library/tasks.html"><code>colliderml.tasks</code></a> package at startup:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> colliderml.tasks </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _tasks</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">TASKS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _tasks.list_tasks()</span></span></code></pre></div><p>Adding a new task in the library is enough to surface it in the UI — no Space redeploy beyond a pin-bump on the <code>colliderml</code> package in <code>requirements.txt</code>.</p><p>The Space falls back to a hardcoded task list if the <code>colliderml</code> import fails (e.g. during a first-boot partial install).</p><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>Submission and reproduction both require a HuggingFace OAuth sign-in. The received token is forwarded as a bearer credential to the <code>/v1/benchmark/&lt;task&gt;/submit</code> and <code>/v1/benchmark/&lt;task&gt;/reproduce/&lt;id&gt;</code> backend endpoints. Browsing the rankings does <strong>not</strong> require a sign-in.</p><h2 id="credit-economics" tabindex="-1">Credit economics <a class="header-anchor" href="#credit-economics" aria-label="Permalink to &quot;Credit economics&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Action</th><th style="text-align:left;">Reward</th></tr></thead><tbody><tr><td style="text-align:left;">Submit a new best on any metric</td><td style="text-align:left;">30–50 credits (task-dependent)</td></tr><tr><td style="text-align:left;">Add a new baseline that becomes the bar to beat</td><td style="text-align:left;">100 credits</td></tr><tr><td style="text-align:left;">Reproduce a submission within 2% tolerance on every metric</td><td style="text-align:left;">20 credits</td></tr><tr><td style="text-align:left;">Contribute a new task or channel</td><td style="text-align:left;">200 credits</td></tr></tbody></table><p>Credit balances are shared across every entry point in the platform (the pip package, the Simulation Form Space, and this Space all draw from the same backend ledger).</p><h2 id="required-space-secrets" tabindex="-1">Required Space secrets <a class="header-anchor" href="#required-space-secrets" aria-label="Permalink to &quot;Required Space secrets&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Secret</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>COLLIDERML_BACKEND</code></td><td style="text-align:left;">Backend URL; defaults to <code>https://api.colliderml.com</code></td></tr></tbody></table><h2 id="running-it-locally" tabindex="-1">Running it locally <a class="header-anchor" href="#running-it-locally" aria-label="Permalink to &quot;Running it locally&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spaces/leaderboard</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install -r requirements.txt</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> COLLIDERML_BACKEND</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost:8000</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.py</span></span></code></pre></div><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../guide/tasks.html">Benchmark Tasks guide</a> — the conceptual tour</li><li><a href="./../library/tasks.html"><code>colliderml.tasks</code></a> — the registry that populates the task tabs</li><li><a href="./simulation-form.html">Simulation Form</a> — for generating training data</li></ul>`,22)]))}const u=t(r,[["render",l]]);export{k as __pageData,u as default};
